import{_ as e,o as a,c as d,a2 as o}from"./chunks/framework.kxxRO88J.js";const p=JSON.parse('{"title":"3장. Codex로 모션 그래픽 만들기","description":"","frontmatter":{"sidebar_position":1},"headers":[],"relativePath":"03-codex-motion/index.md","filePath":"03-codex-motion/index.md"}'),r={name:"03-codex-motion/index.md"};function i(n,t,l,h,s,c){return a(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="_3장-codex로-모션-그래픽-만들기" tabindex="-1">3장. Codex로 모션 그래픽 만들기 <a class="header-anchor" href="#_3장-codex로-모션-그래픽-만들기" aria-label="Permalink to &quot;3장. Codex로 모션 그래픽 만들기&quot;">​</a></h1><h2 id="이-챕터의-핵심" tabindex="-1">이 챕터의 핵심 <a class="header-anchor" href="#이-챕터의-핵심" aria-label="Permalink to &quot;이 챕터의 핵심&quot;">​</a></h2><p>이 챕터는 이 블로그에서 가장 중요한 부분입니다. Codex 프롬프트를 사용해 텍스트 애니메이션, 도형 애니메이션, 씬 전환, 이미지·로고 삽입까지 실제 모션 그래픽의 주요 요소를 모두 만들어봅니다.</p><p>코드를 처음부터 작성할 필요 없습니다. 각 페이지에서 제공하는 Codex 프롬프트를 복사해 사용하면 됩니다.</p><hr><h2 id="이-챕터의-구성" tabindex="-1">이 챕터의 구성 <a class="header-anchor" href="#이-챕터의-구성" aria-label="Permalink to &quot;이 챕터의 구성&quot;">​</a></h2><table tabindex="0"><thead><tr><th>페이지</th><th>내용</th><th>핵심 기술</th></tr></thead><tbody><tr><td><a href="./prompt-basics.html">1. 프롬프트 작성법</a></td><td>좋은 프롬프트 vs 나쁜 프롬프트</td><td>프롬프트 구조화</td></tr><tr><td><a href="./text-animation.html">2. 텍스트 애니메이션</a></td><td>페이드인, 슬라이드업, 타이프라이터</td><td><code>interpolate</code>, <code>spring</code></td></tr><tr><td><a href="./shape-animation.html">3. 도형 애니메이션</a></td><td>그라디언트, 원형, 다중 요소</td><td><code>interpolateColors</code>, <code>@remotion/shapes</code></td></tr><tr><td><a href="./transitions.html">4. 씬 전환</a></td><td>fade, slide, wipe 트랜지션</td><td><code>@remotion/transitions</code></td></tr><tr><td><a href="./assets.html">5. 에셋 사용</a></td><td>이미지, 로고 삽입</td><td><code>staticFile()</code></td></tr></tbody></table><hr><h2 id="이-챕터를-마치면" tabindex="-1">이 챕터를 마치면 <a class="header-anchor" href="#이-챕터를-마치면" aria-label="Permalink to &quot;이 챕터를 마치면&quot;">​</a></h2><ul><li>Codex 프롬프트로 모션 그래픽 씬을 생성할 수 있습니다</li><li>텍스트와 도형에 다양한 애니메이션을 적용할 수 있습니다</li><li>여러 씬을 전환 효과와 함께 연결할 수 있습니다</li><li>이미지와 로고를 영상에 삽입할 수 있습니다</li></ul><p>4장에서는 Remotion 공식 프롬프트 쇼케이스에서 실제 예제를 보고 커스터마이징하는 방법을 다룹니다.</p>',11)])])}const x=e(r,[["render",i]]);export{p as __pageData,x as default};
